SELECT schedule_id, staff_id, work_date, start_time, end_time,
       available_status, create_time, update_time
FROM schedule

    AND staff_id = #{staffId}
    AND work_date >= #{startDate}
    AND work_date <= #{endDate}
    AND available_status = #{availableStatus}

ORDER BY work_date DESC, start_time DESC

SELECT schedule_id, staff_id, work_date, start_time, end_time,
       available_status, create_time, update_time
FROM schedule
WHERE staff_id = #{staffId}
  AND work_date = #{workDate}
  AND (
      (start_time < #{endTime} AND end_time > #{startTime})
  )

      AND schedule_id <> #{excludeScheduleId}

mapper.update:
UPDATE schedule
staff_id = #{staffId}, work_date = #{workDate}, start_time = #{startTime}, end_time = #{endTime}, available_status = #{availableStatus},
WHERE schedule_id = #{scheduleId}
